import java.util.Base64;
import java.util.List;
import java.util.ArrayList;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class ContentMigrator {

    public String migrateContent(String multipartContent) {
        StringBuilder result = new StringBuilder();
        String[] parts = multipartContent.split("--boundary");

        for (String part : parts) {
            if (part.contains("text/html")) {
                String htmlContent = extractContent(part);
                result.append(htmlContent);
            } else if (part.contains("image/")) {
                String base64Image = extractBase64Image(part);
                if (base64Image != null) {
                    result.append("<img src=\"data:image/png;base64,").append(base64Image).append("\"/>");
                }
            }
        }
        return result.toString();
    }

    private String extractContent(String part) {
        Pattern pattern = Pattern.compile("(?s)(?<=\r\n\r\n)(.*?)(?=\r\n--boundary)");
        Matcher matcher = pattern.matcher(part);
        if (matcher.find()) {
            return matcher.group(1);
        }
        return "";
    }

    private String extractBase64Image(String part) {
        Pattern pattern = Pattern.compile("(?s)(?<=\r\n\r\n)(.*?)(?=\r\n--boundary)");
        Matcher matcher = pattern.matcher(part);
        if (matcher.find()) {
            return matcher.group(1);
        }
        return null;
    }
}
